import os
import boto3

def fetch_latest_model_from_s3(bucket_name, model_path):
    s3_client = boto3.client('s3')
    paginator = s3_client.get_paginator('list_objects_v2')
    response_iterator = paginator.paginate(Bucket=bucket_name, Prefix=model_path)

    latest_model = None
    latest_date = None

    for page in response_iterator:
        if 'Contents' in page:
            for obj in page['Contents']:
                if latest_date is None or obj['LastModified'] > latest_date:
                    latest_date = obj['LastModified']
                    latest_model = obj['Key']

    if latest_model:
        local_path = os.path.join('/tmp', os.path.basename(latest_model))
        s3_client.download_file(bucket_name, latest_model, local_path)
        return local_path
    else:
        raise Exception("No model found in specified path.")

def load_model(local_model_path):
    import joblib
    return joblib.load(local_model_path)

def main():
    model_path = os.environ.get('MODEL_PATH')
    if not model_path:
        raise EnvironmentError("Environment variable MODEL_PATH not set.")

    bucket_name, prefix = model_path.split('/', 1)
    local_model_path = fetch_latest_model_from_s3(bucket_name, prefix)
    model = load_model(local_model_path)
    return model

